select count(*) from postgres.posthistory as ph, postgres.posts as p, postgres.users as u, postgres.badges as b where b.userid = u.id and p.owneruserid = u.id and ph.userid = u.id and ph.posthistorytypeid=2 and ph.creationdate>=timestamp '2011-01-08 03:03:48' and ph.creationdate<=timestamp '2014-08-25 14:04:43' and p.answercount<=4 and p.commentcount>=0 and p.commentcount<=12 and p.favoritecount>=0 and p.favoritecount<=89 and p.creationdate<=timestamp '2014-09-02 10:21:04' and u.reputation<=705 and u.creationdate>=timestamp '2010-07-28 23:56:00' and u.creationdate<=timestamp '2014-09-02 10:04:41' and b."date">=timestamp '2010-07-20 20:47:27' and b."date"<=timestamp '2014-09-09 13:24:28';
